{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem requires finding a sequence of sibling merges to transform one tree into another. This is a structural transformation problem that can be broken down into identifying which nodes must be merged and in what order to satisfy the 'larger value survives' and 'union of children' rules.",
  "helpers": [
    {
      "label": "structural_analyzer",
      "instructions": "Analyze the initial and final tree structures to identify which nodes in the initial tree are siblings that must be merged to match the final tree. Specifically, for each parent in the final tree, identify which set of nodes in the initial tree correspond to its children. Determine which initial nodes are 'lost' because they were merged into a larger sibling."
    },
    {
      "label": "dependency_scheduler",
      "instructions": "Given a set of required merges (where merging node A and B results in max(A, B)), determine a valid execution order. A merge can only occur if both nodes are currently siblings and have not been merged into something else yet. Ensure that if a node is a child of a node that needs to be merged, the child's subtree is processed or preserved according to the rules."
    },
    {
      "label": "implementation_engineer",
      "instructions": "Write the main.py script. Use the structural analysis to identify merge pairs and the scheduler to order them. The code must handle multiple test cases, read the tree edges for both initial and final states, and output the number of operations followed by the pairs of node values being merged. Ensure the logic respects the rule that the larger value survives the merge."
    }
  ],
  "synthesis_brief": "Combine the list of required merge pairs from the structural_analyzer with the valid execution order from the dependency_scheduler to produce the final sequence of operations for the implementation_engineer to output."
}

